// Time:  O(n)
// Space: O(1)

class Solution {
public:
    string truncateSentence(string s, int k) {
        for (int i = 0; i < size(s); ++i) {
            if (s[i] == ' ' && --k == 0) {
                return s.substr(0, i);
            }
        }
        return s;
    }
};

# Time:  O(n)
# Space: O(1)

class Solution(object):
    def truncateSentence(self, s, k):
        """
        :type s: str
        :type k: int
        :rtype: str
        """
        for i in xrange(len(s)):
            if s[i] == ' ':
                k -= 1
                if not k:
                    return s[:i]
        return s
